const dg = $json;
const meta = $('IA Metadata').item.json.metadata || {};
const picked = $('Pick Media File').item.json;

const alt = dg?.results?.channels?.[0]?.alternatives?.[0];
const words = alt?.words || [];
const wordText = (w) => (w.punctuated_word || w.word || '');

const turns = [];
let cur = null;
for (const w of words) {
  const spk = (w.speaker === undefined ? 0 : w.speaker);
  if (!cur || cur.speaker !== spk) { cur = { speaker: spk, text: '' }; turns.push(cur); }
  cur.text += wordText(w) + ' ';
}
const turnsText = turns.map(t => `[Speaker ${t.speaker}]: ${t.text.trim()}`).join('\n');
const speakerNumbers = [...new Set(words.map(w => (w.speaker === undefined ? 0 : w.speaker)))].sort((a, b) => a - b);

let description = meta.description;
if (Array.isArray(description)) description = description.join(' ');
description = String(description || '').replace(/<[^>]+>/g, ' ').replace(/\s+/g, ' ').trim().slice(0, 1500);

const title = picked.title || meta.title || picked.identifier;

return {
  json: {
    identifier: picked.identifier,
    title,
    mediaUrl: picked.mediaUrl,
    description: description || '(none provided)',
    speakerNumbers,
    turnsText,
    // carried through for Assemble:
    words,
    duration: dg?.metadata?.duration ?? null,
    language: dg?.results?.channels?.[0]?.detected_language || 'en',
  },
};

