parameters.jsCode:
// ---- inputs (all from the merged item) ----
const identifier = $json.identifier;
const title = $json.title || identifier;
const mediaUrl = $json.mediaUrl;
const words = $json.words || [];
const duration = $json.duration ?? null;
const language = $json.language || 'en';

// ---- speaker labels from the Structured Output Parser ----
let speakers = {};
const parsed = $json.output ?? {};
const arr = parsed.speakers || (Array.isArray(parsed) ? parsed : []);
for (const e of arr) {
  if (e && e.speaker !== undefined) speakers[e.speaker] = e;
}

// ---- normalise labels: Narrator / Unknown speaker N / ≤20 chars ----
{
  const keys = Object.keys(speakers).map(Number).sort((a, b) => a - b);
  let unknownCount = 0;
  for (const k of keys) {
    const s = speakers[k];
    if (!s?.label) continue;
    let lbl = String(s.label).trim();
    if (/narrator|voice[- ]?over/i.test(lbl)) {
      lbl = 'Narrator';
    } else if (/^(unknown|unidentified|unclear)/i.test(lbl)) {
      unknownCount++;
      lbl = `Unknown speaker ${unknownCount}`;
    } else if (lbl.length > 20) {
      lbl = lbl.slice(0, 17) + '…';
    }
    speakers[k] = { ...s, label: lbl };
  }
}

const labelFor = (n) => (speakers[n] && speakers[n].label) ? speakers[n].label : `Speaker ${n}`;

// ---- sentence-anchor speakers (smooth diarization at sentence boundaries) ----
const wordText = (w) => (w.punctuated_word || w.word || '');
function smoothSpeakers(arr) {
  if (!arr.length) return;
  const ends = (w) => {
    const t = wordText(w);
    const lc = t.charAt(t.length - 1);
    return lc === '.' || lc === '?' || lc === '!';
  };
  let start = 0;
  for (let i = 0; i < arr.length; i++) {
    if (ends(arr[i]) || i === arr.length - 1) {
      const tally = {};
      for (let j = start; j <= i; j++) {
        const k = arr[j].speaker ?? 0;
        tally[k] = (tally[k] || 0) + 1;
      }
      let winner = null, max = -1;
      for (const k in tally) if (tally[k] > max) { max = tally[k]; winner = +k; }
      for (let j = start; j <= i; j++) arr[j].speaker = winner;
      start = i + 1;
    }
  }
}
smoothSpeakers(words);

// ---- build Hyperaudio transcript ----
const maxWordsInPara = 100;
const significantGapInSeconds = 4.0;
const ms = (s) => Math.round(s * 1000);
const esc = (s) => String(s).replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;').replace(/"/g,'&quot;');
const showDiarization = words.some((w) => w.speaker !== undefined);

let ht = `<article>\n <section data-media-src="${esc(mediaUrl)}">\n  <p>\n   `;
let prevEnd = 0, inPara = 0;
words.forEach((el, i) => {
  inPara++;
  if ((prevEnd !== 0 && (el.start - prevEnd) > significantGapInSeconds) || inPara > maxWordsInPara) {
    const pw = wordText(words[i - 1]);
    const lc = pw.charAt(pw.length - 1);
    if (lc === '.' || lc === '?' || lc === '!') { ht += "\n  </p>\n  <p>\n   "; inPara = 0; }
  }
  if (showDiarization && i > 0 && el.speaker !== words[i - 1].speaker) { ht += "\n  </p>\n  <p>\n   "; inPara = 0; }
  if (showDiarization && (i === 0 || el.speaker !== words[i - 1].speaker)) {
    ht += `<span class="speaker" data-m='${ms(el.start)}' data-d='0'>${esc(labelFor(el.speaker))} </span>\n   `;
  }
  ht += `<span data-m='${ms(el.start)}' data-d='${ms(el.end - el.start)}'>${esc(wordText(el))} </span>\n   `;
  prevEnd = el.end;
});
ht += "\n </p> \n </section>\n</article>\n";
ht = ht.replace(/<p>\s*<\/p>\s*/g, '');

// ---- metadata JSON ----
const metadata = {
  identifier, title, mediaUrl,
  source: `https://archive.org/details/${identifier}`,
  duration, language, speakers,
  generatedAt: new Date().toISOString(),
};

return {
  json: {
    identifier,
    files: [
      {
        path: `src/data/transcripts/${identifier}.html`,
        content: ht,
        kind: 'html',
        identifier,
      },
      {
        path: `src/data/transcripts/${identifier}.json`,
        content: JSON.stringify(metadata, null, 2),
        kind: 'json',
        identifier,
      },
    ],
  },
};
